typography:
interface TypographyProps {
  variant?: Variant;
  as?: keyof React.JSX.IntrinsicElements;
  className?: string;
  children?: React.ReactNode;
}

badge:
interface BadgeProps {
  variant?: "primary" | "secondary" | "success" | "warning";
  size?: "sm" | "md" | "lg";
  shape?: "rounded" | "squared";
  children: React.ReactNode;
  className?: string;
}

chip:
interface ChipProps {
  variant?: "primary" | "secondary" | "outline";
  size?: "sm" | "md" | "lg";
  icon?: React.ReactNode;
  disabled?: boolean;
  onRemove?: () => void;
  className?: string;
  children: React.ReactNode;
}

button:
interface ButtonProps {
  variant?: "primary" | "secondary" | "outline" | "icon";
  size?: "sm" | "md" | "lg";
  iconBefore?: React.ReactNode;
  iconAfter?: React.ReactNode;
  disabled?: boolean;
  className?: string;
  children?: React.ReactNode;
  onClick?: () => void;
  "aria-label"?: string;
}

card:
interface CardProps {
  id?: string;
  title: string | React.ReactNode;
  subtitle?: string;
  description?: string;
  content?: React.ReactNode;
  className?: string;
  titleClassName?: string;
  subtitleClassName?: string;
  descriptionClassName?: string;
  size?: "sm" | "md" | "lg" | "compact";
  animated?: boolean;
  showBorder?: boolean;
  showCorners?: boolean;
  shadow?: "none" | "sm" | "md" | "lg" | "glow";
  showDivider?: boolean;
  children?: React.ReactNode;
  coverImage?: string;
  coverImageAlt?: string;
  clickable?: boolean;
  onClick?: () => void;
}

table:
interface TableProps {
  columns: TableColumn[];
  data: Record<string, React.ReactNode>[];
  striped?: boolean;
  bordered?: boolean;
  compact?: boolean;
  className?: string;
}

divider:
interface DividerProps {
  spacing?: "sm" | "md" | "lg";
  label?: React.ReactNode;
  className?: string;
}

dialog:
interface DialogProps {
  open: boolean;
  onClose: () => void;
  title?: string | React.ReactNode;
  footer?: React.ReactNode;
  size?: "sm" | "md" | "lg";
  closeOnOverlayClick?: boolean;
  className?: string;
  children?: React.ReactNode;
}

drawer:
interface DrawerProps {
  open: boolean;
  onClose: () => void;
  title?: string | React.ReactNode;
  footer?: React.ReactNode;
  side?: "left" | "right" | "top" | "bottom";
  size?: "sm" | "md" | "lg";
  closeOnOverlayClick?: boolean;
  className?: string;
  children?: React.ReactNode;
}

text-field:
interface TextFieldProps {
  label?: string;
  type?: string;
  value: string;
  onChange: (value: string) => void;
  error?: string;
  placeholder?: string;
  rows?: number;
  className?: string;
}

radio-group:
interface RadioGroupProps {
  label: string;
  options: RadioOption[];
  value: string;
  onChange: (value: string) => void;
  error?: string;
  name?: string;
  className?: string;
}

select:
interface SelectProps {
  label: string;
  options: SelectOption[];
  value: string;
  onChange: (value: string) => void;
  error?: string;
  className?: string;
}

status-bar:
interface StatusBarProps {
  progress: number;
  status?: string;
}

dropdown-menu:
interface DropdownMenuProps {
  trigger: React.ReactNode;
  groups: DropdownGroup[];
  align?: "left" | "right";
  className?: string;
}

tabs:
interface TabsProps {
  tabs: Tab[];
  activeTab: string;
  onTabChange: (tabId: string) => void;
  className?: string;
  animated?: boolean;
  contentHeight?: string | number;
  mobileBottomMenu?: boolean;
}

nav-list:
interface NavListProps {
  tabs: NavListItem[];
  defaultActiveTab?: string;
  className?: string;
  tabsClassName?: string;
  contentClassName?: string;
  animated?: boolean;
  horizontal?: boolean;
}

timeline:
interface TimelineProps {
  items: TimelineItem[];
  className?: string;
  animated?: boolean;
  selectedId?: string;
  onSelect?: (id: string) => void;
}

screen-center-wrapper:
interface ScreenCenterWrapperProps {
  children: React.ReactNode;
  className?: string;
}
